from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    subjects = list(subject_map.keys())
    for i in range(len(subjects)):
        subject = subjects[i]
        if sentence:
            sentence += ", which "
        else:
            sentence += f"{subject} "

        predicates = subject_map[subject]
        location_predicates = []
        other_predicates = []
        for predicate, obj in predicates:
            if predicate == "cityServed":
                location_predicates.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                other_predicates.append(f"has a mayor of {obj}")
            elif predicate == "isPartOf":
                location_predicates.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                other_predicates.append(f"is operated by {obj}")
            elif predicate == "location":
                location_predicates.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                other_predicates.append(f"is {obj} metres above sea level")
            elif predicate == "runwayLength":
                other_predicates.append(f"has a runway length of {obj} metres")
            elif predicate == "country":
                location_predicates.append(f"is located in {obj}")
            elif predicate == "capital":
                other_predicates.append(f"has {obj} as its capital")
            elif predicate == "language":
                other_predicates.append(f"has {obj} as its official language")
            elif predicate == "leader":
                other_predicates.append(f"has {obj} as its leader")
            elif predicate == "owner":
                other_predicates.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                other_predicates.append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                other_predicates.append(f"has a first runway with {obj} surface")
            elif predicate == "3rdRunwayLengthFeet":
                other_predicates.append(f"has a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                other_predicates.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                other_predicates.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                other_predicates.append(f"is {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                other_predicates.append(f"has an IATA location identifier of {obj}")
            elif predicate == "nativeName":
                other_predicates.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                other_predicates.append(f"has a leader party of {obj}")
            elif predicate == "runwayName":
                other_predicates.append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                other_predicates.append(f"has a runway surface type of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                other_predicates.append(f"is {obj} metres above sea level")
            elif predicate == "runwayLength":
                other_predicates.append(f"has a runway length of {obj} metres")
            else:
                other_predicates.append(f"has a {predicate} of {obj}")

        if location_predicates or other_predicates:
            if location_predicates:
                sentence += ", ".join(location_predicates)
            if other_predicates:
                if location_predicates:
                    sentence += " and "
                sentence += ", ".join(other_predicates)

    # Connect related triples into a single sentence
    for i in range(len(subjects) - 1):
        subject = subjects[i]
        next_subject = subjects[i + 1]
        for predicate, obj in subject_map[subject]:
            if next_subject == obj:
                sentence = sentence.replace(f"{subject} which {next_subject}", f"{subject} which is {next_subject}")
            elif predicate == "cityServed" and next_subject in obj:
                sentence = sentence.replace(f"{subject} which serves the city of {obj}", f"{subject} which serves the city of {obj} where {next_subject} is located")

    return sentence + "."
